  'sgirat-tikim': 'sgirat-tikim',
  'guides': 'guides',
  'compare': 'comparisons',
  'amuta': 'amuta',
  'cities': 'cities'
};
function inferCategory(idea) {
  if (idea.category) return idea.category;
  const url = idea.parent_page_url || idea.source_page_url || '';
  for (const [key, val] of Object.entries(CATEGORY_MAP)) {
    if (url.includes('/' + key)) return val;
  }
  return 'osek-patur';
}
const ideaCategory = inferCategory(idea);
const today = new Date().toISOString().split('T')[0];

